import{c as t,Q as e,j as o,m as i}from"./chunks/framework.BPKcPtvA.js";const s="/screenshots/statistics.png",g=JSON.parse('{"title":"Statistics","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/statistics.md","filePath":"guide/using-librislog/statistics.md","lastUpdated":1779853505000}'),r={name:"guide/using-librislog/statistics.md"};function n(d,a,h,l,u,c){return e(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="statistics" tabindex="-1">Statistics <a class="header-anchor" href="#statistics" aria-label="Permalink to &quot;Statistics&quot;">​</a></h1><p>The statistics page provides insights into your reading habits with charts, totals, and visualizations.</p><h2 id="overview-cards" tabindex="-1">Overview Cards <a class="header-anchor" href="#overview-cards" aria-label="Permalink to &quot;Overview Cards&quot;">​</a></h2><p>At the top of the statistics page, four key metrics are displayed:</p><p><img src="'+s+'" alt="Statistics Overview" loading="lazy"></p><table tabindex="0"><thead><tr><th>Metric</th><th>Description</th></tr></thead><tbody><tr><td><strong>Avg Books/Month</strong></td><td>Average number of books finished per month</td></tr><tr><td><strong>Busiest Month</strong></td><td>The month with the most books finished</td></tr><tr><td><strong>Avg Page Count</strong></td><td>Average number of pages across all books</td></tr><tr><td><strong>Most Popular Language</strong></td><td>The language you read most (based on book count)</td></tr></tbody></table><h2 id="distribution-charts" tabindex="-1">Distribution Charts <a class="header-anchor" href="#distribution-charts" aria-label="Permalink to &quot;Distribution Charts&quot;">​</a></h2><h3 id="language-distribution" tabindex="-1">Language Distribution <a class="header-anchor" href="#language-distribution" aria-label="Permalink to &quot;Language Distribution&quot;">​</a></h3><p>A stacked bar showing the proportion of books by language. Colors represent different languages, with a legend below the chart.</p><h3 id="status-distribution" tabindex="-1">Status Distribution <a class="header-anchor" href="#status-distribution" aria-label="Permalink to &quot;Status Distribution&quot;">​</a></h3><p>A stacked bar showing how your library is divided among the four reading statuses:</p><ul><li>Want to Read (blue)</li><li>Currently Reading (yellow)</li><li>Read (green)</li><li>Did Not Finish (red)</li></ul><h3 id="page-buckets" tabindex="-1">Page Buckets <a class="header-anchor" href="#page-buckets" aria-label="Permalink to &quot;Page Buckets&quot;">​</a></h3><p>A stacked bar showing:</p><ul><li><strong>Pages to Read</strong> — Total pages in &quot;Want to Read&quot; books</li><li><strong>Pages Read</strong> — Total pages in &quot;Read&quot; books</li><li><strong>Pages Wasted</strong> — Pages read in &quot;Did Not Finish&quot; books</li></ul><h2 id="bar-charts" tabindex="-1">Bar Charts <a class="header-anchor" href="#bar-charts" aria-label="Permalink to &quot;Bar Charts&quot;">​</a></h2><p>Three bar charts show trends over time:</p><h3 id="pages-read-per-month" tabindex="-1">Pages Read Per Month <a class="header-anchor" href="#pages-read-per-month" aria-label="Permalink to &quot;Pages Read Per Month&quot;">​</a></h3><p>Bar chart showing total pages read each month. Based on page counts of books marked as &quot;Read&quot; in that month.</p><h3 id="books-finished-per-month" tabindex="-1">Books Finished Per Month <a class="header-anchor" href="#books-finished-per-month" aria-label="Permalink to &quot;Books Finished Per Month&quot;">​</a></h3><p>Bar chart showing the number of books finished each month.</p><h3 id="books-finished-per-year" tabindex="-1">Books Finished Per Year <a class="header-anchor" href="#books-finished-per-year" aria-label="Permalink to &quot;Books Finished Per Year&quot;">​</a></h3><p>Bar chart showing the number of books finished each year.</p><p>All bar charts support zoom and pan interactions. Click the reset button to restore the default view.</p><h2 id="calendar-heatmap" tabindex="-1">Calendar Heatmap <a class="header-anchor" href="#calendar-heatmap" aria-label="Permalink to &quot;Calendar Heatmap&quot;">​</a></h2><p>A GitHub-style calendar heatmap shows daily reading activity:</p><ul><li>Each square represents one day</li><li>Color intensity indicates pages read that day</li><li>Darker colors = more pages</li><li>Hover for exact page count</li></ul><p>The heatmap is based on reading progress entries, not just book finish dates, so you can see daily reading patterns.</p><h2 id="top-authors" tabindex="-1">Top Authors <a class="header-anchor" href="#top-authors" aria-label="Permalink to &quot;Top Authors&quot;">​</a></h2><p>The top 3 authors by book count are displayed with:</p><ul><li>Author name and rank badge</li><li>Book count</li><li>Up to 5 cover images from their books (click to open book details)</li></ul><h2 id="data-sources" tabindex="-1">Data Sources <a class="header-anchor" href="#data-sources" aria-label="Permalink to &quot;Data Sources&quot;">​</a></h2><p>Statistics are computed from:</p><ul><li>Book metadata (page counts, languages, statuses)</li><li>Reading progress entries (for calendar heatmap and timeline)</li><li>Book finish dates (for monthly/yearly charts)</li></ul><p>All statistics are calculated server-side and updated in real-time when you modify your library.</p>',35)])])}const b=t(r,[["render",n]]);export{g as __pageData,b as default};
